var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"도착했어, 여기가 전시관이야.","JPN":"着いたよ、ミナ。ここが展示会場だって。","ENG":"We're here. This is the gallery.","TWN":"到了，這裡就是展覽館。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응? 전시관에 벌써부터 사람들이 모여있는데? 무슨 일이지?","JPN":"あれ、会場の前に人だかりが出来てる。なにかあったのかな？","ENG":"Hmm? It's already packed with people. Is something going on?","TWN":"嗯？怎麼已經有人聚集在展覽館裡？是發生什麼事？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"아무리 그래도 그렇지! 이건 너무하잖아!?","JPN":"いくら何でもこれはひどすぎる！！","ENG":"Hey, you can't be serious! You crossed a line here!","TWN":"怎麼可以這樣！會不會太過分！？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ART_NPC_GEASS_NULL","text":{"KOREA":"대체 무슨 헛소리를 하는 건데, 진짜!","JPN":"いったい何を言ってるんだ！　まったく！","ENG":"I seriously have no clue what you're talking about!","TWN":"你在胡說什麼？放尊重點！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저건 사진부랑 미술부잖아?","JPN":"あれは写真部と美術部？","ENG":"Isn’t that the photography club and art club?","TWN":"他們不是攝影部和美術部的人嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"뭔가 문제가 터졌나보네, 서두르자!","JPN":"早速トラブルになってる。急ごう！","ENG":"Looks like something's up. Let's hurry!","TWN":"好像出事了，我們快去看看！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"지금이라도 사실대로 말해? 너희가 그런 거잖아!?","JPN":"今からでも正直に言えよ。そっちの仕業だろ？","ENG":"Just admit it already! You're the ones who did it!","TWN":"可以請你說實話嗎？明明就是你們做的！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ART_NPC_GEASS_NULL","text":{"KOREA":"트집 잡는 것도 적당히 좀 하라고! 우리가 왜 너희 사진을 왜 감췄다는 건데?","JPN":"言いがかりも、いい加減にしてくれ。\\n私たちがそっちの写真を隠してどうするんだ。","ENG":"What are you accusing us of, huh? Why would we steal and hide your club's photos?","TWN":"少在那邊含血噴人！我們幹嘛要把你們的照片藏起來？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"잠깐, 둘 다 우선 진정해. 학생회에서 왔어.","JPN":"待って待って、ふたりとも。まずは落ち着いて。\\n私たちは生徒会よ。","ENG":"Whoa, let's calm down a little. We're from the Student Council.","TWN":"等等，大家先冷靜一下，我們是學生會派來的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"무슨 일이 있었는지 알려줄래?","JPN":"何があったか教えて。","ENG":"Can you tell me what's going on here?","TWN":"可以說明一下發生什麼事嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"그러니까 사진부에서 전시 예정이었던 사진들이 갑자기 모두 사라졌다는 거야?","JPN":"つまり、写真部で展示予定だった写真が全部消えてしまったってこと？","ENG":"So, all of your photos that were going to be displayed suddenly disappeared?","TWN":"所以意思就是攝影部原本要展出的照片突然全都消失不見嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"그래! 분명 이 녀석들 짓이 틀림없어!","JPN":"ああ！　きっとこいつらの仕業に違いない！","ENG":"Yeah! And the culprits are right there!","TWN":"沒錯！一定是他們做的啦！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ART_NPC_GEASS_NULL","text":{"KOREA":"그러니까 우리가 왜 그런 짓을 하는데?","JPN":"だから、どうして私たちが\\nそんなことをする必要があるって言うんだ！","ENG":"Like I said, why would we do such a thing?","TWN":"我們到底為什麼要那麼做啦？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"그야, 전시관을 독차지하려고 그런 거겠지!","JPN":"そりゃあ、展示会場を独占したいからだろ！","ENG":"So you'd have the gallery all to yourselves!","TWN":"還不就你們想霸佔展覽館！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ART_NPC_GEASS_NULL","text":{"KOREA":"증거라도 있어? 애초에 너희들 실수로 잃어버린 거 아니야? 그걸 왜 미술부 탓을 하는 건데?","JPN":"証拠はあるのか？\\nそもそも自分たち写真部のミスで紛失したんじゃないのか？　それを美術部のせいにするなんて……","ENG":"You've got proof? Why are you blaming us when it's obviously your fault that you lost them?!","TWN":"你有證據嗎？根本是你們自己搞丟的吧？還想賴到美術部頭上來？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"두 사람 다 그만해.","JPN":"二人とも、ケンカはやめなさい。","ENG":"The two of you, stop it.","TWN":"你們都少說一句！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"카렌, 우리는 사진부의 요청으로 여기 온 거니까 사진부가 사진 찾는 걸 도와주자.","JPN":"カレン。私たちは写真部の依頼でここに来たんだし、\\n無くなった写真探しに協力しよう。","ENG":"Kallen, we're here at the photography club's request. Let's help them look for their photos.","TWN":"卡蓮，我們是受攝影部之託來的，就幫攝影部找回照片吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"그래, 아무래도 사진을 찾지 못하면 싸움을 말릴 수 없을 것 같아.","JPN":"そうね。写真を見つけない限り、このトラブルは収まりそうにないものね。","ENG":"Yeah, I don't think they'll stop fighting unless we find them.","TWN":"嗯嗯，不把照片找回來的話，我看事情是不會結束的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응. 그리고 전시 준비도 해야 해. 서두르자.","JPN":"うん。展示の準備もあるから、早く見つけないと。急ごう。","ENG":"Right. And we need to hurry because we need time to prepare for the exhibition.","TWN":"嗯，而且還要預備展出，動作要快。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"어때, 미나? 찾았어?","JPN":"どう、ミナ？　見つかった？","ENG":"Any luck, Mina?","TWN":"怎麼樣，米娜？有找到嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니. 사진부가 알려준 사진이 있을 법한 장소는 전부 찾아봤는데 없었어.","JPN":"いや、写真部が教えてくれた\\n写真のありそうな場所は全部探したけど見つからなかった。","ENG":"No. I looked everywhere the photography club members told me to, but no dice.","TWN":"沒有，攝影部說照片可能會在的地方我全都找過了，但都沒看到。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"그러니까 말했잖아. 누군가가 우리 사진을 훔쳐간 거라고.","JPN":"だから言ったじゃないか。誰かが俺たちの写真を盗んだって。","ENG":"I'm telling you. Somebody stole our photos.","TWN":"我不是說了嗎？是有人把我們的照片偷走了！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"자, 알겠지? 이제 시간이 없어. 지금이라도 미술부 녀석들한테 따지러 가자.","JPN":"これでわかっただろう？　もう時間がない。\\n今からでも美術部のやつらを問い詰めて返してもらおう。","ENG":"Now, you understand? We don't have time. Let's go confront the art club about it.","TWN":"沒錯吧？沒時間了，快去找美術部的人問清楚吧！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"잠깐, 누군가 사진을 훔쳐갔다고 해도 그게 정말 미술부라는 증거는 있어?","JPN":"待って。誰かに写真を盗まれたとしても、\\n犯人が美術部だという証拠はないでしょう？","ENG":"Wait. Even if somebody really did steal them, how can you be sure that it was the art club?","TWN":"我想問，你說有人偷走照片，那你有證據證明是美術部偷的嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"그, 그건…….","JPN":"そ、それは……","ENG":"Th-that's because...","TWN":"這個，我……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"부탁이야. 학생회! 이대로 올해 전시를 망칠 수는 없다고!","JPN":"お願いだ、生徒会！\\nこのまま今年の展示会を台無しにするわけにはいかないんだ！","ENG":"I'm begging you, Student Council! I can't afford to have this year's exhibition ruined like this!","TWN":"我拜託你們！今年的展出絕對不能就這樣毀掉！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"걱정 마. 다행히 전시회까지는 아직 하루가 남았잖아?","JPN":"ああ、幸い展示会まではまだ一日ある。","ENG":"Don't worry. We still have a day to find them, no?","TWN":"你放心，幸好距離展出還有一天的時間。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"를르슈? 여긴 어쩐 일이야?","JPN":"ルルーシュ？　どうしてここに？","ENG":"Lelouch? What are you doing here?","TWN":"魯路修？你怎麼會來？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"뭐, 전체 행사의 진행 상황을 감독하는 것도 실행위원장의 일이니까.","JPN":"各部の進捗を把握するのも実行委員長の仕事だからな。","ENG":"I'm overseeing the festival preparations as the head of the executive committee.","TWN":"因為監督整體活動進度也是執行委員長的任務之一。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"부장, 전시 예정인 사진이 사라졌다는 이야기는 들었어. 방송부에 전달했으니 누군가 발견한다면 연락이 올 거야.","JPN":"部長、展示予定だった写真が消えたという話は聞いている。\\n放送部にもアナウンスしてもらっているから、誰かが写真を見つけたら連絡してくれるだろう。","ENG":"I heard that the photos for the exhibition have gone missing. I've notified the broadcast club, so they'll contact you if anyone finds them.","TWN":"社長，我聽說攝影部預計要展出的照片不見了，我已經請人廣播，有人發現照片就會聯絡你。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"카렌, 네가 를르슈한테 부탁한 거야?","JPN":"カレン、あなたがルルーシュに話したの？","ENG":"Kallen, did you ask for help from Lelouch?","TWN":"卡蓮，是你通知魯路修的嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"응? 아니…… 아마 다른 사진부원이 먼저 연락한 거 아닐까?","JPN":"えっ？　違うけど……写真部の部員が連絡したんじゃないかしら。","ENG":"Hmm? No... I'm guessing it was one of the photography club members?","TWN":"嗯？不是我……應該是其他攝影部的人通知他的吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"사진을 되찾는 건 틀렸어. 하루 종일 찾았던 사진이 갑자기 어디서 툭 튀어나오겠어.","JPN":"写真を取り戻すのは無理だ。\\n今までこれだけ時間をかけて探したのに出てこなかったんだから。","ENG":"We're not going to find them. We've looked for them all day and nothing. It's not like they're gonna suddenly appear out of thin air.","TWN":"照片找不回來了啦，我們都找一天了，怎麼可能突然就冒出來？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"음, 맞는 말이야. 어쩌면 이제와서 사진을 되찾는 건 무리일지도 모르지.","JPN":"うむ。そうだな。\\n無くなった写真を見つけ出すのは厳しいのかもしれない。","ENG":"Mm, you're right. Perhaps recovering the missing photos is near impossible.","TWN":"嗯，你說的有道理，照片或許是無法失而復得。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"하지만 전시회라고 해서 미리 찍어 둔 사진만 전시해야 한다는 규칙은 없었잖아?","JPN":"しかし、展示会には事前に撮った写真しか展示できない、という\\nルールはないんだろう？","ENG":"But there is no rule about having to display only pre-taken photos at the exhibition, right?","TWN":"但誰規定只能展出預先拍好的照片呢？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"응? 그게 무슨 소리야?","JPN":"はあ。それってどういう意味だい？","ENG":"Huh? What do you mean?","TWN":"嗯？你那是什麼意思？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"미나, 카렌. 두 사람 다 잠깐 도와주겠어?","JPN":"ミナ、カレン。二人とも少し手伝ってもらうぞ。","ENG":"Mina, Kallen. Could you help me for a second?","TWN":"米娜、卡蓮，我需要你們的幫忙。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"ART_NPC_GEASS_NULL","text":{"KOREA":"……결국, 사진부 녀석들 사진 못 찾은 모양이네. 괜히, 우리한테 트집이나 잡고 말이야.","JPN":"……結局写真部の連中、写真を見つけられなかったみたいだな。\\nふん。私たちに言いがかりをつけてなんていたからだ。","ENG":"...Guess the photography club never found their photos. But how dare they accuse us of stealing them.","TWN":"……結果是攝影部自己找不到照片，還硬要找我們的碴。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ART_NPC_GEASS_NULL","text":{"KOREA":"자, 그럼 슬슬 미술부의 작품을 걸어 볼까?","JPN":"さて、そろそろ美術部の絵の展示を準備しよう。","ENG":"Okay, we should start hanging up our work.","TWN":"來吧，大家把美術部的作品掛上去吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ART_NPC_GEASS_NULL","text":{"KOREA":"뭐야? 저 사람들은?","JPN":"何だ、あの人だかりは？","ENG":"Huh? Aren't those...?","TWN":"嗯？他們在幹嘛？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ART_NPC_GEASS_NULL","text":{"KOREA":"대체 무슨 일로 저렇게 모여있는 거지?","JPN":"いったい何があって、あんなに集まっているんだ？","ENG":"Why are they all gathered over there?","TWN":"什麼事啊？怎麼那麼多人擠在那裡？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"좋아! 좋다고, 유미나! 아주 매력적인 피사체야.","JPN":"いい！　いいぞ、ヤナギ・ミナ！\\n君は被写体としての素質がある。","ENG":"Good! Perfect, Mina! You're so photogenic!","TWN":"很好！非常好！劉米娜！你真是非常有魅力的模特兒！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_WINTER_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_CAMERA"},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_WINTER_NULL","text":{"KOREA":"그, 그런가?","JPN":"そ、そうかな？","ENG":"R-really?","TWN":"是，是嗎？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_WINTER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"자, 그런 수줍어하는 표정도 좋지만, 그 자세 그대로 활짝 웃어볼래?","JPN":"その少しはにかんだ表情もいいが、そのままさりげなく、笑顔を！","ENG":"Okay, I like how you blush, but could you stay in that pose and give us a smile instead?","TWN":"再來一張，害羞的表情也很不錯，但你可以保持同一個姿勢笑得燦爛一點嗎？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_WINTER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_WINTER_NULL","text":{"KOREA":"이, 이렇게……?","JPN":"こ、こう……？","ENG":"L-like this...?","TWN":"這，這樣嗎……？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_WINTER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"응, 딱 좋아! 이제 다른 자세도 좀 취해 봐!","JPN":"うん。いいね！　いくつかポーズをとってくれるかい。","ENG":"Perfect! Now, how about we switch poses?","TWN":"嗯！非常好！接下來再換個姿勢！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_WINTER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"우와, 저게 누구야? 프로 모델인가 봐.","JPN":"わあ、あれは誰かしら？　プロのモデルさんかな？","ENG":"Whoa, who's that? She's like a professional model.","TWN":"哇，那是誰啊？好像是專業模特兒欸？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_WINTER_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"우리 학교에 저런 미인이 있었나? 사진부 애는 아닌 것 같은데?","JPN":"うちの学校にあんな美人いたっけ？　写真部の子じゃなさそうだし。","ENG":"She's really pretty, was she always in our school? I don't think she's a part of the photography club.","TWN":"我們學校有這種大美女喔？好像不是攝影部的？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_WINTER_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"설마, 즉석에서 촬영회를 생각해 낼 줄은 몰랐는데.","JPN":"まさか、即席で写真撮影会を始めちゃうとはね。","ENG":"I can't believe you thought of holding a mini photoshoot on the spot.","TWN":"沒想到你竟然會想到現場開攝影展。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"전시할 것이 사라졌다면, 전시할 것을 만들면 그만이니까.","JPN":"展示するものがなくなったのなら、展示するものを用意すればいい。","ENG":"If there's nothing to display, one can always create more.","TWN":"要是原本要展示的東西不見，那就創造新的就好啦。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"뭐, 다행히 사진은 그림과 달라서 촬영하고 즉시 출력이 가능하지.","JPN":"幸い、写真は絵と違って、撮影すれば、すぐにプリントできる。","ENG":"Fortunately, photos are easier to print and display than drawings.","TWN":"不過幸好照片跟畫不一樣，可以拍好就立刻洗出來。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"그렇게 출력한 사진을 전시한다면 어쨌든 전시회로서도 성립이 된다는 말이네.","JPN":"プリントした写真を展示すれば、展示会として成り立つ、ってワケね。","ENG":"So even with last-minute prints, they'll be able to have their exhibition.","TWN":"將現場拍好的照片展示出來，也算是有展出到吧？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"사진부 쪽에서는 자기들이 미리 준비한 사진을 전시하고 싶을지도 모르겠지만…….","JPN":"本当は、準備した写真を展示したいだろうがな……","ENG":"They probably wanted to show off the work that disappeared, but...","TWN":"不過攝影部的人或許會想展出原本準備好的照片吧……"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"글쎄, 내 생각에는 사진부 녀석들도 이 촬영회를 그리 싫어하지는 않는 것 같은데?","JPN":"そうかもしれないけど、この撮影会も悪くはないみたいよ。","ENG":"Who knows? From what I'm seeing, they don't seem to mind this photoshoot.","TWN":"不知道欸，但我覺得他們似乎也不討厭這個攝影展？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"응? ","JPN":"うん？","ENG":"Hmm? ","TWN":"嗯？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"농담하지 마! 이런 옷 입고 컨셉 촬영한다는 말은 안 했잖아!?","JPN":"冗談じゃない！\\nこんな服を着てコンセプト撮影するなんて話は聞いてないよ！？","ENG":"You gotta be kidding me! You never said anything about wearing this ridiculous costume!","TWN":"你在開什麼玩笑！當初可沒說要穿成這樣拍沙龍照！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"자, 잠깐! 유미나! 내 얘기를 좀 들어봐! 이것도 다 전시회를 위해서라고!","JPN":"ま、待って！　ミナ！　話だけでも聞いてくれ！\\nこれも展示会のためなんだ！","ENG":"W-wait, Yoo Mina! Just hear me out! This is all for the exhibition!","TWN":"哎，哎呀！劉米娜！你先聽我說完！這也都是為了攝影展啦！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아무리 그래도…… 어째서 이런 옷을 빌려 온 건데? 방금처럼 평범한 옷도 있었잖아?","JPN":"そ、それを言われると……でも、これって……\\nさっきみたいな普通の服じゃダメなの？","ENG":"But still... Why does it have to be this costume? You had perfectly normal clothes too!","TWN":"就算是這樣……為什麼要借這種衣服？剛剛不是穿得很正常嗎？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"당연하잖아. 예술을 위해서야! 너처럼 완벽한 피사체에게 어울리는 복장은 바로 이거라고!","JPN":"ダメだ。芸術のためなんだ！\\n君のような素晴らしい被写体に相応しい衣装なんだ！","ENG":"Well, of course! It's art! I believe you are the perfect model for this costume!","TWN":"這不是很正常嗎？為藝術犧牲啊！適合你這種完美模特兒的衣服，就是這件啦！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으으…….","JPN":"うう……","ENG":"Ngh...","TWN":"呃……"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"거봐, 내 말이 맞지?","JPN":"ね？","ENG":"See? What did I tell you?","TWN":"你看，我說的沒錯吧？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"사진부가 의욕을 되찾은 건 좋다만, 아무래도 뭔가 문제가 일어난 것 같은데?","JPN":"ああ。写真部が乗り気なのは安心したが、何かトラブルが起きてないか？","ENG":"Looks like they're in high spirits, but it seems like there's a problem.","TWN":"攝影部能找回活力是很好，但好像有什麼問題的樣子？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"으~음. 그게. 문제라고 한다면 문제일까나.","JPN":"う～ん。そうね。トラブルと言えば、トラブルかも。","ENG":"Hmm. But is it really a problem?","TWN":"嗯～該說是問題嗎？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"카렌, 미나가 계속 모델을 하는 건 꽤 힘들어보이는데, 네가 교대해주는 건 어때?","JPN":"そうだ、カレン。\\nミナ一人では疲れてしまうだろうから、お前も協力するというのは……","ENG":"Kallen, Mina looks pretty drained from all the modeling. How about you take her place for a bit?","TWN":"卡蓮，米娜看起來好像拍得有點累的樣子，還是你跟她換一下？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"하, 하하. 미안하지만 난 패스야. 왜냐하면 아까 사진부 부장이……","JPN":"悪いけどパスかな。だって、さっき写真部の部長が……","ENG":"Hah, hah hah. Sorry, but I'll pass. Because I saw the photography club prepare...","TWN":"哈哈哈，不好意思，我不行。剛才攝影部社長……"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"역시 이건 이상하잖아! 어째서 바니걸이냐고!","JPN":"やっぱり変だよ！　これってバニーガールの衣装じゃないの！？","ENG":"This isn't right! Why does it have to be a bunny girl?!","TWN":"這不對吧！為什麼是兔女郎！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L11_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"바, 바니걸……?","JPN":"バ、バニーガール……","ENG":"B-bunny girl...?","TWN":"兔女郎……？"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"그래. 아까 사진부 부장이 저걸 준비하는 걸 봐버렸거든.","JPN":"そう。\\nさっき写真部の部長が、あの衣装を用意してるのを見ちゃったんだよね。","ENG":"Yeah, I saw them prepare that outfit.","TWN":"對，我剛有看到攝影部社長在準備服裝。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"무, 뭐어…… 미나와 부장이 서로 납득했다면 괜찮을지도. 크흠.","JPN":"ま、まあ。彼らが納得しているならいいか。","ENG":"W-what...? I mean, if they came to an agreement, I guess it's fine. Ahem.","TWN":"那，那個……只要米娜和社長都可以接受的話，應該是沒什麼關係，咳咳。"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"전혀 괜찮지 않다고……!!","JPN":"よくなーい！","ENG":"It's not fine at all...!!","TWN":"我很有關係……！！"},"stage":{"bg":"CLUB1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"쳇, 어쩔 수 없겠네.","JPN":"くっ。もう腹を括るしかないわね。","ENG":"Tch, I guess I have no choice.","TWN":"嘖，隨你們吧！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"네가 예술을 이해해줘서 다행이야.","JPN":"芸術を理解してくれて助かるよ。","ENG":"Thanks for understanding our vision.","TWN":"幸好你可以理解藝術。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"알았으니까, 얼른 찍고 끝내.","JPN":"わかったから、さっさと撮って終わらせて。","ENG":"Fine. Let's just get it over with already.","TWN":"懂懂懂，趕快拍一拍啦。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"응? 이 기억은 뭐지……?","JPN":"えっ？　この記憶は何……？","ENG":"Huh? Whose memory was that...?","TWN":"嗯？這個記憶是……？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"전에도…… 내가 바니걸을 입었던 적이 있었나? 언제?","JPN":"前にも……バニーガールの衣装を着たことあったっけ？　いつ？","ENG":"Have I... worn a bunny girl suit before? But when?","TWN":"我之前……也扮過兔女郎嗎？什麼時候？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"미나? 유미나?","JPN":"ミナ？　ヤナギ・ミナ！","ENG":"Mina? Yoo Mina?","TWN":"米娜？劉米娜？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PHOTO_NPC_GEASS_NULL","text":{"KOREA":"괜찮아? 이제 다른 포즈를 좀 부탁하고 싶은데…….","JPN":"大丈夫か？　次のポーズをお願いしたいんだが……","ENG":"You okay? I just wanted to ask if you could change your pose...","TWN":"你還好嗎？想請你換個姿勢……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_VAL_NULL","text":{"KOREA":"아, 아아. 응. 아무것도 아니야. 신경쓰지 마.","JPN":"あ、ああ。うん。何でもない、気にしないで。","ENG":"Oh, o-okay. Sure. It's nothing. Don't worry about it.","TWN":"喔喔喔，嗯，沒事，別擔心。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_VAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};